# Quick combinatorial verification for small n:
# A connected complement graph H on n>=3 has no isolated vertex and no connected component of size 2.
# Original Gamma has universal vertex iff H has isolated vertex.
# Original nonedge {v,w} adjacent to all other vertices iff H edge {v,w} is a component of size 2.
import itertools
def connected(n, edges):
    adj=[set() for _ in range(n)]
    for i,j in edges:
        adj[i].add(j); adj[j].add(i)
    seen={0}; stack=[0]
    while stack:
        v=stack.pop()
        for u in adj[v]:
            if u not in seen:
                seen.add(u); stack.append(u)
    return len(seen)==n
for n in range(3,7):
    verts=range(n)
    all_edges=list(itertools.combinations(verts,2))
    for mask in range(1,1<<len(all_edges)):
        edges=[all_edges[k] for k in range(len(all_edges)) if mask>>k &1]
        if connected(n, edges):
            deg=[0]*n
            for i,j in edges:
                deg[i]+=1;deg[j]+=1
            assert min(deg)>=1
            # no edge component of size 2: an edge whose endpoints have deg1 and no other vertices reachable (would be disconnected)
            for i,j in edges:
                assert not (deg[i]==deg[j]==1 and n>2)
print("checked small n")
